import{_ as e,o as l,c as r,a2 as a}from"./chunks/framework.Crpw6aS5.js";const y=JSON.parse('{"title":"扩展阅读","description":"巴菲特相关的演讲、访谈、纪录片、历史文档等资源集合","frontmatter":{"title":"扩展阅读","description":"巴菲特相关的演讲、访谈、纪录片、历史文档等资源集合"},"headers":[],"relativePath":"07_resources/index.md","filePath":"07_resources/index.md"}'),d={name:"07_resources/index.md"};function n(s,t,h,f,o,i){return l(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="扩展阅读" tabindex="-1">扩展阅读 <a class="header-anchor" href="#扩展阅读" aria-label="Permalink to &quot;扩展阅读&quot;">​</a></h1><p>欢迎来到巴菲特知识库的扩展阅读区。这里汇集了来自全球各地的经典资源，包括大学演讲、深度访谈、纪录片以及珍贵的历史文档，帮助你从多个维度理解巴菲特的投资智慧。</p><hr><h2 id="📚-演讲-lectures-约10小时" tabindex="-1">📚 演讲 Lectures（约10小时） <a class="header-anchor" href="#📚-演讲-lectures-约10小时" aria-label="Permalink to &quot;📚 演讲 Lectures（约10小时）&quot;">​</a></h2><p>巴菲特在世界各地大学的经典演讲，涵盖投资哲学、商业分析和人生智慧。</p><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">演讲</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">1992</td><td style="text-align:left;">奥马哈新闻俱乐部演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=bZOMSYXIt0Y" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">1996</td><td style="text-align:left;">北卡罗来纳大学演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=qGe46Paihuo" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">1998</td><td style="text-align:left;">佛罗里达大学演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=7Z6x-Ov1smU" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">1998</td><td style="text-align:left;">华盛顿大学演讲（与比尔·盖茨）</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=ldPh0_zEykU" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">1999</td><td style="text-align:left;">内布拉斯加大学林肯分校演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=HM9h9t1vpIE" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2001</td><td style="text-align:left;">乔治亚大学演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=2a9Lx9J8uSs" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2003</td><td style="text-align:left;">内布拉斯加大学林肯分校演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=9x8Z1M-B9IA" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2005</td><td style="text-align:left;">内布拉斯加大学演讲（与比尔·盖茨）</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=1AlPTiJrJnE" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2013</td><td style="text-align:left;">乔治城大学演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=6JLoU1BRdeE" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2018</td><td style="text-align:left;">高盛演讲</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=pNNJpf_hicE" target="_blank" rel="noreferrer">YouTube</a></td></tr></tbody></table><blockquote><p>💡 <strong>推荐</strong>：佛罗里达大学演讲（1998）和乔治城大学演讲（2013）是公认的经典，巴菲特在演讲中详细阐述了他的投资框架。</p></blockquote><hr><h2 id="🎤-访谈-interviews-约30小时" tabindex="-1">🎤 访谈 Interviews（约30小时） <a class="header-anchor" href="#🎤-访谈-interviews-约30小时" aria-label="Permalink to &quot;🎤 访谈 Interviews（约30小时）&quot;">​</a></h2><p>从1980年代到2022年，跨越四十年的深度访谈记录。</p><h3 id="经典系列访谈" tabindex="-1">经典系列访谈 <a class="header-anchor" href="#经典系列访谈" aria-label="Permalink to &quot;经典系列访谈&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">访谈</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">1980s</td><td style="text-align:left;">与Adam Smith第一次访谈</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=8OcegOGAGIs" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">1980s</td><td style="text-align:left;">与Adam Smith第二次访谈</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=UMVlOS8KODk" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">1999</td><td style="text-align:left;">Nightline专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=jPJXQ3FqPLk" target="_blank" rel="noreferrer">YouTube</a></td></tr></tbody></table><h3 id="charlie-rose-系列专访" tabindex="-1">Charlie Rose 系列专访 <a class="header-anchor" href="#charlie-rose-系列专访" aria-label="Permalink to &quot;Charlie Rose 系列专访&quot;">​</a></h3><p>Charlie Rose对巴菲特进行了多次深度访谈，是了解巴菲特思想演变的珍贵资料：</p><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">2006年第一部分</td><td style="text-align:left;"><a href="https://charlierose.com/videos/12653" target="_blank" rel="noreferrer">观看</a></td></tr><tr><td style="text-align:left;">2006年第二部分</td><td style="text-align:left;"><a href="https://charlierose.com/videos/21205" target="_blank" rel="noreferrer">观看</a></td></tr><tr><td style="text-align:left;">2006年第三部分</td><td style="text-align:left;"><a href="https://charlierose.com/videos/18066" target="_blank" rel="noreferrer">观看</a></td></tr><tr><td style="text-align:left;">2008年</td><td style="text-align:left;"><a href="https://charlierose.com/videos/11747" target="_blank" rel="noreferrer">观看</a></td></tr><tr><td style="text-align:left;">2009年</td><td style="text-align:left;"><a href="https://charlierose.com/videos/22046" target="_blank" rel="noreferrer">观看</a></td></tr><tr><td style="text-align:left;">2011年</td><td style="text-align:left;"><a href="https://charlierose.com/videos/13532" target="_blank" rel="noreferrer">观看</a></td></tr><tr><td style="text-align:left;">2012年</td><td style="text-align:left;"><a href="https://charlierose.com/videos/17620" target="_blank" rel="noreferrer">观看</a></td></tr><tr><td style="text-align:left;">2022年</td><td style="text-align:left;"><a href="https://charlierose.com/videos/31221" target="_blank" rel="noreferrer">观看</a></td></tr></tbody></table><h3 id="媒体专访精选" tabindex="-1">媒体专访精选 <a class="header-anchor" href="#媒体专访精选" aria-label="Permalink to &quot;媒体专访精选&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">媒体</th><th style="text-align:left;">主题</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">2009</td><td style="text-align:left;">Bloomberg</td><td style="text-align:left;">金融危机后的思考</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=_UQ5Nl6wco8" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2010</td><td style="text-align:left;">Forbes</td><td style="text-align:left;">与Jay-Z对谈商业</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=01Q9R7Da-hI" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2011</td><td style="text-align:left;">财富杂志</td><td style="text-align:left;">投资理念</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=yzuTj_t7ILs" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2011</td><td style="text-align:left;">财富杂志</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=FSqUYQ-vubM" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2011</td><td style="text-align:left;">NDTV India</td><td style="text-align:left;">印度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=e9aHFZPxEz8" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2011</td><td style="text-align:left;">YouTube</td><td style="text-align:left;">与Charlie Rose对话</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=xVOn371TCPo" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2012</td><td style="text-align:left;">财富杂志</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=uKBZgMW-p_c" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2012</td><td style="text-align:left;">David Rubenstein</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=KuYBeBCx19g" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2014</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">关于可口可乐</td><td style="text-align:left;"><a href="https://buffett.cnbc.com/video/2014/05/05/buffett-well-never-want-to-go-to-war-with-coca-cola-full-interview.html" target="_blank" rel="noreferrer">CNBC</a></td></tr><tr><td style="text-align:left;">2014</td><td style="text-align:left;">Crain&#39;s Detroit</td><td style="text-align:left;">底特律商业</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=lqGhGsqmXU0" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2014</td><td style="text-align:left;">财富杂志 MPW</td><td style="text-align:left;">女性力量峰会</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=cSU3y0N60XU" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2015</td><td style="text-align:left;">ASU</td><td style="text-align:left;">与Jeff Cunningham对谈</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=2-e3Wm68DaA" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2015</td><td style="text-align:left;">财富杂志 MPW</td><td style="text-align:left;">女性力量峰会</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=kqI29Jv-uH0" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2016</td><td style="text-align:left;">David Rubenstein</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=u8ANHNU0Fng" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2016</td><td style="text-align:left;">CNN</td><td style="text-align:left;">商业专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=ezLH1Yo7J-w" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2017</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">市场观点</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=kIycWPECFDc" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2017</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=BXrYDGPUSF4" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2017</td><td style="text-align:left;">Purpose Built Communities</td><td style="text-align:left;">社区建设</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=p9P7cZNAcX0" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2018</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">与Jamie Dimon对谈</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=MLyCdxc-wfA" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2018</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">生日专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=9kke_CGNpFE" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2019</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=Pqc56crs56s" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2019</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">与芒格和盖茨</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=2hdDE7XYr30" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2019</td><td style="text-align:left;">Yahoo Finance</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=SEZwkbliJr8" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2020</td><td style="text-align:left;">CNBC</td><td style="text-align:left;">疫情后的思考</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=JvEas_zZ4fM" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2020</td><td style="text-align:left;">Yahoo Finance</td><td style="text-align:left;">深度专访</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=2KUuTbSPG8s" target="_blank" rel="noreferrer">YouTube</a></td></tr></tbody></table><hr><h2 id="🎬-纪录片-documentaries-约3小时" tabindex="-1">🎬 纪录片 Documentaries（约3小时） <a class="header-anchor" href="#🎬-纪录片-documentaries-约3小时" aria-label="Permalink to &quot;🎬 纪录片 Documentaries（约3小时）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">纪录片</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">2009</td><td style="text-align:left;">The World&#39;s Greatest Moneymaker: Warren Buffett</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=w-eX4sZi-Zs" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2010</td><td style="text-align:left;">Bloomberg Game Changers: Warren Buffett</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=Grgraon4p40" target="_blank" rel="noreferrer">YouTube</a></td></tr><tr><td style="text-align:left;">2017</td><td style="text-align:left;">Becoming Warren Buffett (HBO纪录片)</td><td style="text-align:left;"><a href="https://www.youtube.com/watch?v=n_AODFjCNI4" target="_blank" rel="noreferrer">YouTube</a></td></tr></tbody></table><blockquote><p>🌟 <strong>强烈推荐</strong>：《成为沃伦·巴菲特》(2017) 是HBO制作的权威纪录片，深入展现了巴菲特的成长历程和投资理念。</p></blockquote><hr><h2 id="📄-珍贵历史文档-126页" tabindex="-1">📄 珍贵历史文档（126页） <a class="header-anchor" href="#📄-珍贵历史文档-126页" aria-label="Permalink to &quot;📄 珍贵历史文档（126页）&quot;">​</a></h2><p>这些文档记录了巴菲特在不同时期的重要观点和行动。</p><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">文档</th><th style="text-align:left;">说明</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">1975</td><td style="text-align:left;">致Kay Graham关于养老金的信</td><td style="text-align:left;">巴菲特为华盛顿邮报设计的养老金投资方案</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2020/10/Buffett-Letter-to-Kay-Graham-about-Pensions.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1982</td><td style="text-align:left;">致国会议员关于衍生品的信</td><td style="text-align:left;">对金融衍生品的早期警告</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2021/08/Warren-Buffett-on-Derivatives.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2010</td><td style="text-align:left;">金融危机调查委员会访谈记录</td><td style="text-align:left;">巴菲特对金融危机的证词</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/10/2010-05-26-Transcript-of-Interview-With-Warren.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr></tbody></table><hr><h2 id="📨-巴菲特合伙企业致股东信-1957-1970" tabindex="-1">📨 巴菲特合伙企业致股东信（1957-1970） <a class="header-anchor" href="#📨-巴菲特合伙企业致股东信-1957-1970" aria-label="Permalink to &quot;📨 巴菲特合伙企业致股东信（1957-1970）&quot;">​</a></h2><p>这是巴菲特在投资生涯早期写给合伙人的信件，记录了他从零开始建立投资帝国的过程。<strong>共152页</strong>。</p><p>巴菲特在1956年创立了巴菲特合伙企业，1970年解散并将资产并入伯克希尔。这些信件展现了他早期的投资策略和思维方式，是理解巴菲特投资演变的珍贵资料。</p><p><a href="https://www.ivey.uwo.ca/media/2975913/buffett-partnership-letters.pdf" target="_blank" rel="noreferrer">📥 下载完整PDF</a></p><hr><h2 id="📜-巴菲特的-失落信件-1970-1976" tabindex="-1">📜 巴菲特的&quot;失落信件&quot;（1970-1976） <a class="header-anchor" href="#📜-巴菲特的-失落信件-1970-1976" aria-label="Permalink to &quot;📜 巴菲特的&quot;失落信件&quot;（1970-1976）&quot;">​</a></h2><p>这些是在伯克希尔转型期的年报，被称为&quot;失落信件&quot;，因为它们相对鲜为人知。<strong>共232页</strong>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">1970年报</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/09/1970-Berkshire-AR.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1971年报</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/09/1971-Berkshire-AR.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1972年报</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/09/1972-Berkshire-AR.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1973年报</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/09/1973-Berkshire-AR.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1974年报</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/09/1974-Berkshire-AR.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1975年报</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/09/1975-Berkshire-AR.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1976年报</td><td style="text-align:left;"><a href="https://theoraclesclassroom.com/wp-content/uploads/2019/09/1976-Berkshire-AR.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr></tbody></table><hr><h2 id="📮-伯克希尔哈撒韦致股东信-1977-2023" tabindex="-1">📮 伯克希尔哈撒韦致股东信（1977-2023） <a class="header-anchor" href="#📮-伯克希尔哈撒韦致股东信-1977-2023" aria-label="Permalink to &quot;📮 伯克希尔哈撒韦致股东信（1977-2023）&quot;">​</a></h2><p>这是巴菲特投资生涯的核心文档，每年一封，共<strong>550+页</strong>，记录了他构建伯克希尔帝国近半个世纪的思考。</p><h3 id="早期信件-1977-1990" tabindex="-1">早期信件（1977-1990） <a class="header-anchor" href="#早期信件-1977-1990" aria-label="Permalink to &quot;早期信件（1977-1990）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">1977</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1977.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1984</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1984.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1978</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1978.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1985</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1985.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1979</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1979.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1986</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1986.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1980</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1980.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1987</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1987.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1981</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1981.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1988</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1988.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1982</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1982.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1989</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1989.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1983</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1983.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1990</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1990.html" target="_blank" rel="noreferrer">阅读</a></td></tr></tbody></table><h3 id="_90年代信件-1991-2000" tabindex="-1">90年代信件（1991-2000） <a class="header-anchor" href="#_90年代信件-1991-2000" aria-label="Permalink to &quot;90年代信件（1991-2000）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">1991</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1991.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1996</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1996.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1992</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1992.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1997</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1997.html" target="_blank" rel="noreferrer">阅读</a></td></tr><tr><td style="text-align:left;">1993</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1993.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1998</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1998pdf.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1994</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1994.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">1999</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/final1999pdf.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">1995</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/1995.html" target="_blank" rel="noreferrer">阅读</a></td><td style="text-align:left;">2000</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2000pdf.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr></tbody></table><h3 id="_21世纪信件-2001-2023" tabindex="-1">21世纪信件（2001-2023） <a class="header-anchor" href="#_21世纪信件-2001-2023" aria-label="Permalink to &quot;21世纪信件（2001-2023）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th><th style="text-align:left;">年份</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">2001</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2001pdf.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2009</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2009ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2017</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2017ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2002</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2002pdf.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2010</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2010ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2018</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2018ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2003</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2003ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2011</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2011ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2019</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2019ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2004</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2004ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2012</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2012ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2020</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2020ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2005</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2005ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2013</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2013ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2021</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2021ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2006</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2006ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2014</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2014ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2022</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2022ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2007</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2007ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2015</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2015ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2023</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2023ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td></tr><tr><td style="text-align:left;">2008</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2008ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;">2016</td><td style="text-align:left;"><a href="https://www.berkshirehathaway.com/letters/2016ltr.pdf" target="_blank" rel="noreferrer">PDF</a></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr></tbody></table><hr><h2 id="📖-推荐书籍" tabindex="-1">📖 推荐书籍 <a class="header-anchor" href="#📖-推荐书籍" aria-label="Permalink to &quot;📖 推荐书籍&quot;">​</a></h2><p>除了视频和文档，以下书籍也是深入理解巴菲特的必读之作：</p><h3 id="巴菲特著作" tabindex="-1">巴菲特著作 <a class="header-anchor" href="#巴菲特著作" aria-label="Permalink to &quot;巴菲特著作&quot;">​</a></h3><ul><li><strong>《巴菲特致股东的信》</strong> - 巴菲特历年股东信合集，价值投资的圣经</li><li><strong>《巴菲特传：滚雪球》</strong> - 艾丽斯·施罗德著，巴菲特授权的权威传记</li></ul><h3 id="芒格著作" tabindex="-1">芒格著作 <a class="header-anchor" href="#芒格著作" aria-label="Permalink to &quot;芒格著作&quot;">​</a></h3><ul><li><strong>《穷查理宝典》</strong> - 查理·芒格的智慧箴言，巴菲特的&quot;幕后大脑&quot;</li></ul><h3 id="价值投资经典" tabindex="-1">价值投资经典 <a class="header-anchor" href="#价值投资经典" aria-label="Permalink to &quot;价值投资经典&quot;">​</a></h3><ul><li><strong>《聪明的投资者》</strong> - 本杰明·格雷厄姆著，巴菲特的&quot;投资圣经&quot;</li><li><strong>《证券分析》</strong> - 格雷厄姆与多德著，价值投资的奠基之作</li></ul><hr><h2 id="💡-学习建议" tabindex="-1">💡 学习建议 <a class="header-anchor" href="#💡-学习建议" aria-label="Permalink to &quot;💡 学习建议&quot;">​</a></h2><ol><li><strong>按时间线阅读</strong>：建议从合伙企业信件开始，追踪巴菲特思想的演变</li><li><strong>结合视频学习</strong>：先看演讲和访谈建立整体认知，再深入阅读信件</li><li><strong>重点关注</strong>：佛罗里达大学演讲（1998）和HBO纪录片是入门最佳材料</li><li><strong>交叉验证</strong>：将不同年份对同一主题的论述对比阅读，理解巴菲特如何随时间调整观点</li></ol><hr><blockquote><p>📌 <strong>资源来源</strong>：本页面资源整理自 <a href="https://www.carbonfinance.io/p/warren-buffett-repository" target="_blank" rel="noreferrer">Carbon Finance</a> 等公开渠道，仅供学习交流使用。</p></blockquote>',57)])])}const w=e(d,[["render",n]]);export{y as __pageData,w as default};
